xwikidoc.content:
{{velocity}}
#set ($discard = $xwiki.jsx.use('GuidedTour.Tours.WebHome'))
{{html wiki='true'}}
  #set ($sourceParameters = $escapetool.url({
    'className': 'XWiki.GuidedTour.TourClass',
    'translationPrefix': 'guidedtour.livetable.'
  }))
  #set ($liveDataConfig = {
    "meta": {
      "propertyDescriptors": [
        { "id": "title", "displayer": "text" },
        { "id": "isActive", "displayer": "text" },
        { 'id': '_actions', 'displayer': {'id': 'actions', 'actions': ['edit', 'delete', 'view']} }
      ],
      "actions": [
        { 'id': 'edit', "description": "Edit tour" },
        { 'id': 'delete', "description": "Delete tour" },
        { 'id': 'view', "description": "View tour" }
      ]
    }
  })
  {{liveData
    id='guided-tours-overview'
    properties="title,isActive,_actions"
    source='liveTable'
    sourceParameters="$sourceParameters"
    layouts='table'
  }}$jsontool.serialize($liveDataConfig){{/liveData}}
{{/html}}
{{/velocity}}
